pair A, B, C, O, P;

A = (0,0);
B = (2,2);
C = (5,0);
P = interp(B,C,3/8);
O = circumcenter(A,B,C);

draw(A--B--C--cycle);
draw(circumcircle(A,B,C));
draw(O--P);

label("$A$", A, W);
